"use client"

import { useRef } from "react"
import { motion, useInView } from "framer-motion"

const skillCategories = [
  {
    title: "Languages",
    skills: ["TypeScript", "JavaScript", "HTML5", "CSS3"],
  },
  {
    title: "Frameworks & UI",
    skills: ["React", "Next.js", "Tailwind CSS", "Framer Motion", "TanStack Query", "Shadcn UI"],
  },
  {
    title: "Tools & Ecosystem",
    skills: ["Git", "GitHub", "Vercel", "Figma", "VS Code"],
  },
]

export function SkillsSection() {
  const ref = useRef(null)
  const isInView = useInView(ref, { once: true, margin: "-100px" })

  return (
    <section id="skills" className="py-32 scroll-mt-20 border-t border-border bg-muted/30" ref={ref}>
      <div className="max-w-6xl mx-auto px-4 md:px-8">
        <h2 className="text-xs font-mono tracking-widest uppercase text-muted-foreground border-b border-border pb-4 mb-16">
          04. Capabilities
        </h2>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-px bg-border border border-border shadow-sm">
          {skillCategories.map((category, index) => (
            <motion.div
              key={category.title}
              initial={{ opacity: 0, y: 20 }}
              animate={isInView ? { opacity: 1, y: 0 } : { opacity: 0, y: 20 }}
              transition={{ duration: 0.8, delay: index * 0.1, ease: "easeOut" }}
              className="bg-background p-8 md:p-12 hover:bg-muted/50 transition-colors duration-500 flex flex-col"
            >
              <h3 className="text-lg font-bold text-foreground mb-8 uppercase tracking-wide">
                {category.title}
              </h3>
              <ul className="space-y-4 font-mono text-sm text-muted-foreground flex-1">
                {category.skills.map((skill) => (
                  <li key={skill} className="flex items-center justify-between group cursor-crosshair">
                    <span className="group-hover:text-foreground transition-colors duration-300">{skill}</span>
                    <span className="opacity-0 group-hover:opacity-100 transition-opacity duration-300 text-xs">/</span>
                  </li>
                ))}
              </ul>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  )
}
